import { NavLink } from "react-router-dom";
import { LayoutDashboard, Upload, GitBranch, Bug, Brain, FileText, Settings } from "lucide-react";

const items = [
    { to: "/", label: "Dashboard", icon: <LayoutDashboard size={18} /> },
    { to: "/analysis/upload", label: "Upload Code", icon: <Upload size={18} /> },
    { to: "/analysis/pipeline", label: "Analysis", icon: <GitBranch size={18} /> },
    { to: "/vulnerabilities/summary", label: "Vulnerabilities", icon: <Bug size={18} /> },
    { to: "/ai/confidence", label: "AI Insights", icon: <Brain size={18} /> },
    { to: "/reports/executive", label: "Reports", icon: <FileText size={18} /> },
    { to: "/settings/config", label: "Settings", icon: <Settings size={18} /> }
];

export default function Navbar() {
    return (
        <nav style={{
            background: "#0f172a",
            padding: "0 24px",
            borderBottom: "1px solid #1f2937",
            position: "sticky",
            top: 0,
            zIndex: 1000
        }}>
            <div style={{
                display: "flex",
                alignItems: "center",
                gap: 8,
                maxWidth: "1400px",
                margin: "0 auto"
            }}>
                <div style={{
                    fontWeight: "bold",
                    fontSize: "20px",
                    padding: "16px 16px 16px 0",
                    marginRight: 24,
                    color: "#3b82f6"
                }}>
                    HybridGuard
                </div>
                {items.map(i => (
                    <NavLink
                        key={i.to}
                        to={i.to}
                        style={({ isActive }) => ({
                            display: "flex",
                            alignItems: "center",
                            gap: 8,
                            padding: "16px 16px",
                            borderBottom: isActive ? "2px solid #3b82f6" : "2px solid transparent",
                            background: isActive ? "#1f2937" : "transparent",
                            transition: "all 0.2s ease",
                            whiteSpace: "nowrap"
                        })}
                    >
                        {i.icon}
                        <span style={{ fontSize: "14px", color: 'white' }}>{i.label}</span>
                    </NavLink>
                ))}
            </div>
        </nav>
    );
}
